<?php

namespace Database\Seeders;

use App\Models\Faq;
use App\Models\FaqCategory;
use Illuminate\Database\Seeder;

class FaqSeeder extends Seeder
{
    public function run(): void
    {
        $categories = FaqCategory::all()->keyBy('name');

        $faqs = [
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿El subsidio de lactancia es lo mismo que la asignación familiar?', 'answer' => 'No, son beneficios diferentes. El subsidio por lactancia es un pago único de S/ 820 por nacimiento vivo, otorgado por EsSalud. La asignación familiar es un beneficio laboral recurrente pagado por el empleador (generalmente 10% de la RMV) mientras el hijo está en edad escolar o estudios superiores.', 'keywords' => '["subsidio", "lactancia", "mismo", "asignación", "familiar"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Puedo cobrar la lactancia si soy papá soltero?', 'answer' => 'Sí, si la madre ha fallecido o está declarada incapaz, el padre puede cobrar el subsidio por lactancia. Debe presentar el acta de nacimiento, DNI del bebé y documento que acredite la situación (acta de defunción de la madre o resolución judicial de incapacidad).', 'keywords' => '["puedo", "cobrar", "lactancia", "papá", "soltero"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Si la madre trabaja en EsSalud y yo también, cobramos dos lactancias?', 'answer' => 'No. El subsidio por lactancia se paga una sola vez por cada nacido vivo, independientemente de cuántos padres sean asegurados. Se paga a la madre (titular o derechohabiente). Si ambos son asegurados, solo uno puede cobrar.', 'keywords' => '["madre", "trabaja", "essalud", "también", "cobramos", "lactancias"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿La lactancia se paga en dólares o soles?', 'answer' => 'Se paga en soles (S/ 820.00). EsSalud no realiza pagos en moneda extranjera.', 'keywords' => '["lactancia", "paga", "dólares", "soles"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿El subsidio de maternidad se paga aunque el bebé nazca muerto?', 'answer' => 'No. Para que proceda el subsidio por maternidad, el bebé debe haber nacido vivo. Si el nacimiento es sin vida (mortinato), no corresponde subsidio de maternidad, pero sí podría corresponder la prestación por sepelio si el asegurado titular falleció o la prestación por sepelio del recién nacido si estaba registrado como derechohabiente.', 'keywords' => '["subsidio", "maternidad", "paga", "aunque", "bebé", "nazca", "muerto"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Si mi bebé nació el 31 de diciembre, cómo cuentan los 6 meses para cobrar la lactancia?', 'answer' => 'El plazo es calendario, no hábil. Si nació el 31 de diciembre, tiene hasta el 30 de junio del año siguiente para cobrar. No importa si hay feriados o fines de semana de por medio.', 'keywords' => '["bebé", "nació", "diciembre", "cómo", "cuentan", "meses", "cobrar", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Puedo cobrar la lactancia si el bebé nació en el extranjero?', 'answer' => 'Sí, pero el trámite es manual (no es "Cero Trámite"). Debes presentar el acta de nacimiento legalizada por el consulado peruano o apostillada, y traducida si está en otro idioma. El monto sigue siendo S/ 820 por cada hijo.', 'keywords' => '["puedo", "cobrar", "lactancia", "bebé", "nació", "extranjero"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿El subsidio por incapacidad cubre enfermedades mentales?', 'answer' => 'Sí, siempre que un médico (psiquiatra) emita un Certificado de Incapacidad Temporal (CITT) con el diagnóstico correspondiente (código CIE-10 del área de salud mental). El subsidio funciona igual que para cualquier otra enfermedad.', 'keywords' => '["subsidio", "incapacidad", "cubre", "enfermedades", "mentales"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Puedo cobrar ITT si me operaron y tengo descanso de 30 días?', 'answer' => 'Sí, siempre que tengas un CITT emitido por EsSalud o validado. Tu empleador paga los primeros 20 días y EsSalud paga del día 21 al 30. El pago de EsSalud será solo por los 10 días restantes.', 'keywords' => '["puedo", "cobrar", "operaron", "tengo", "descanso", "días"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿El sepelio cubre la cremación o solo entierro?', 'answer' => 'Cubre ambos. La cremación está incluida dentro de los servicios funerarios reconocidos, al igual que el entierro tradicional. El monto máximo es S/ 2,070 para cualquier modalidad.', 'keywords' => '["sepelio", "cubre", "cremación", "solo", "entierro"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Trabajo en construcción, me caí de un andamio y me rompí la pierna. Mi empleador no tiene SCTR. ¿Qué subsidios me corresponden y quién paga?', 'answer' => 'Te corresponde el subsidio por ITT. Los primeros 20 días los paga tu empleador (es su obligación). EsSalud paga desde el día 21 hasta tu recuperación (máx. 11 meses y 10 días). Al no tener SCTR, el empleador puede ser multado y EsSalud puede cobrarle los gastos. No puedes cobrar ITT y SCTR simultáneamente.', 'keywords' => '["trabajo", "construcción", "andamio", "rompí", "pierna", "empleador", "tiene", "sctr"]'],
            ['category_name' => 'Afiliaciones', 'question' => 'Mi esposa dio a luz mellizos en una clínica particular, pero ella no está afiliada a EsSalud (yo sí, soy titular). ¿Cómo cobramos la lactancia?', 'answer' => 'Tú eres el asegurado titular, tu esposa y los mellizos son derechohabientes. Debes inscribirlos primero (presentar actas de nacimiento en OSPE o VIVA). Luego tramitar el subsidio por lactancia (un subsidio por cada hijo, S/ 820 cada uno = S/ 1,640 total). Como fue en clínica particular, es trámite manual (no cero trámite), vía VIVA o presencial. El plazo es 6 meses desde el nacimiento.', 'keywords' => '["esposa", "mellizos", "clínica", "particular", "ella", "está", "afiliada", "essalud"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Estuve de descanso médico 25 días por una operación. Mi empleador me pagó los primeros 20 días pero se niega a pagarme los 5 restantes porque dice que EsSalud debe pagar. ¿Qué hago?', 'answer' => 'Tu empleador está equivocado. Él debe pagarte el subsidio completo (los 25 días) y luego solicitar el reembolso a EsSalud por los días 21-25. Si no te paga, puedes reclamar a SUNAFIL o pedir a EsSalud que te pague directamente desde el día 1 y luego EsSalud le cobrará a tu empleador. Guarda tus comprobantes de pago.', 'keywords' => '["estuve", "descanso", "médico", "días", "operación", "empleador", "pagó", "primeros"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => 'Mi mamá falleció. Era pensionista de EsSalud. Yo pagué su entierro con mis ahorros. ¿Puedo cobrar el sepelio? ¿Cuánto y cómo?', 'answer' => 'Sí, puedes cobrar. Los pensionistas tienen derecho a sepelio. El orden de prelación es: 1° cónyuge, 2° hijos, 3° padres, 4° hermanos. Al no haber cónyuge, tú como hijo puedes cobrar. El monto máximo es S/ 2,070 (reembolso de lo que gastaste hasta ese tope). Debes presentar Formulario 1040, acta de defunción, tus comprobantes de gastos funerarios (a tu nombre) y DNI.', 'keywords' => '["mamá", "falleció", "pensionista", "essalud", "pagué", "entierro", "ahorros", "puedo"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => 'Estoy embarazada de 7 meses, recién me entero que mi empleador no me ha registrado en EsSalud. ¿Qué hago para que me cubran el parto?', 'answer' => 'Las gestantes tienen cobertura inmediata desde la afiliación, pero necesitas que tu empleador te registre YA. Exígele el registro. Si no lo hace, acude a una OSPE con tus boletas de pago y DNI para que te activen manualmente. Si el empleador no pagó aportes, EsSalud igual te atenderá y luego le cobrará a la empresa. No te quedes sin hacer nada; el parto es una urgencia y será atendido.', 'keywords' => '["estoy", "embarazada", "meses", "recién", "entero", "empleador", "registrado", "essalud"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Trabajo como independiente (taxista), tuve un accidente de tránsito, estuve 45 días de descanso. Mi seguro es el potestativo. ¿Qué subsidios me corresponden? ¿Quién paga los primeros 20 días si no tengo empleador?', 'answer' => 'Al ser independiente con seguro potestativo, aplica pago directo de EsSalud. Los primeros 20 días también los paga EsSalud (no hay empleador). El subsidio por ITT cubre desde el día 1 hasta el día 45. Debes tener CITT validado. El accidente de tránsito: primero cubre el SOAT del vehículo responsable, y lo que falte lo cubre EsSalud. Denuncia el accidente a la policía dentro de las 4 horas para el dosaje etílico.', 'keywords' => '["trabajo", "independiente", "taxista", "tuve", "accidente", "tránsito", "estuve", "días"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Mi empleador me pagó los primeros 20 días de incapacidad, pero luego me despidió. Mi incapacidad duró 60 días. ¿Quién paga los días 21 al 60? ¿Sigo teniendo derecho al subsidio si ya no trabajo?', 'answer' => 'Según el D.S. N° 013-2019-TR, la pérdida del vínculo laboral extingue el subsidio. Sin embargo, si el despido ocurrió mientras ya estabas recibiendo el subsidio (después del día 21), algunos criterios indican que puedes seguir cobrando hasta el fin de la incapacidad. Debes consultar con un abogado o reclamar a EsSalud. Lo más probable es que EsSalud deje de pagar desde el despido.', 'keywords' => '["empleador", "pagó", "primeros", "días", "incapacidad", "luego", "despidió", "duró"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Soy trabajadora del hogar, mi empleador no me quiere pagar los primeros 20 días de mi descanso por operación. ¿Qué hago? ¿EsSalud me puede pagar todo desde el día 1?', 'answer' => 'Las trabajadoras del hogar están en la lista de pago directo de EsSalud (Artículo 15 del D.S. N° 013-2019-TR). Esto significa que EsSalud paga desde el día 1, NO aplica que el empleador pague los primeros 20 días. Tu empleador no tiene obligación de pagarte esos días (a menos que quiera hacerlo voluntariamente). Debes tramitar tu subsidio directamente en EsSalud con tu CITT.', 'keywords' => '["trabajadora", "hogar", "empleador", "quiere", "pagar", "primeros", "días", "descanso"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => 'Mi bebé nació con Síndrome de Down. ¿Tengo derecho a los 30 días adicionales de descanso? ¿Cómo lo tramito?', 'answer' => 'Sí, según la Ley N° 29992, el descanso postnatal se extiende por 30 días adicionales cuando el recién nacido tiene discapacidad permanente (incluye Síndrome de Down). El total sería 98 días + 30 = 128 días. Debes presentar un certificado médico que confirme la discapacidad permanente del recién nacido, además de los requisitos habituales del subsidio de maternidad.', 'keywords' => '["bebé", "nació", "síndrome", "down", "tengo", "derecho", "días", "adicionales"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Trabajo en dos empresas (2 empleadores). Tuve una incapacidad de 30 días. ¿Cómo se calcula mi subsidio? ¿Ambos empleadores pagan los primeros 20 días?', 'answer' => 'Debes solicitar un CITT por cada empleador. Cada empleador paga los primeros 20 días de forma independiente. EsSalud paga los días 21-30 de forma proporcional según los aportes de cada empleador. El cálculo del subsidio diario se hace por separado para cada empleador. No puedes cobrar dos veces el mismo día, pero sí recibes el pago proporcional de ambos empleadores.', 'keywords' => '["trabajo", "empresas", "empleadores", "tuve", "incapacidad", "días", "cómo", "calcula"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Puedo afiliarme al potestativo si soy extranjero sin carnet de extranjería?', 'answer' => 'Sí, puedes usar tu Pasaporte o Permiso Temporal de Permanencia (PTP) siempre que esté vigente. Los extranjeros residentes en Perú pueden afiliarse al seguro potestativo.', 'keywords' => '["puedo", "afiliarme", "potestativo", "extranjero", "carnet", "extranjería"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El potestativo cubre chequeos preventivos anuales?', 'answer' => 'Sí, el potestativo incluye prestaciones de prevención y promoción según el PEAS, que contempla chequeos preventivos, vacunas según calendario, tamizajes de cáncer (PAP, VPH), y medición de anemia en niños.', 'keywords' => '["potestativo", "cubre", "chequeos", "preventivos", "anuales"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Si me afilio hoy, puedo sacar cita para la próxima semana?', 'answer' => 'No. Debes cumplir el período de carencia de 3 meses para atenciones regulares. Solo emergencias médicas accidentales están cubiertas desde el primer día (durante las primeras 24 horas). Para una cita programada, espera 3 meses.', 'keywords' => '["afilio", "puedo", "sacar", "cita", "próxima", "semana"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿El potestativo cubre atenciones de odontología?', 'answer' => 'Solo cubre odontología básica señalada en el PEAS (exámenes, limpiezas, extracciones simples). No cubre ortodoncia (brackets) ni periodoncia, excepto lo señalado en el PEAS.', 'keywords' => '["potestativo", "cubre", "atenciones", "odontología"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Puedo cambiar de plan potestativo a regular si encuentro trabajo?', 'answer' => 'Sí. Si encuentras trabajo formal, tu empleador te afiliará al Seguro Regular. El cambio es automático y no pierdes tus derechos acumulados. Debes informar a EsSalud que ya no continuarás con el potestativo para evitar seguir pagando.', 'keywords' => '["puedo", "cambiar", "plan", "potestativo", "regular", "encuentro", "trabajo"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => 'Me afilié al potestativo hace 2 meses. Estoy embarazada de 3 meses (me afilié estando embarazada). ¿Me cubre el parto?', 'answer' => 'No. El contrato del potestativo establece que la cobertura de maternidad requiere que la asegurada esté afiliada al momento de la concepción. Si te afiliaste estando ya embarazada, NO cubre el parto. Además, el período de espera para maternidad es de 10 meses.', 'keywords' => '["afilié", "potestativo", "hace", "meses", "estoy", "embarazada", "estando", "cubre"]'],
            ['category_name' => 'Afiliaciones', 'question' => 'Tengo 65 años, quiero afiliarme al potestativo. ¿Cuánto pago? ¿Tengo período de espera?', 'answer' => 'Pagas S/ 215 mensuales (tarifa para 60 años o más). Sí, tienes período de carencia de 3 meses para cobertura completa. Emergencias accidentales cubren desde el día 1. También aplican períodos de espera para condiciones específicas (10 meses para cáncer, VIH, congénitas, etc.).', 'keywords' => '["tengo", "años", "quiero", "afiliarme", "potestativo", "cuánto", "pago", "período"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Me diagnosticaron cáncer de mama. Estoy en potestativo desde hace 8 meses. ¿Me cubre el tratamiento?', 'answer' => 'No. El período de espera para tratamiento de cáncer es de 10 meses (reducido de 12 por PEAS). Con solo 8 meses de aporte, NO cubre el tratamiento. Sin embargo, el cáncer de mama SÍ está en la lista de cobertura de tratamiento (a diferencia de otros tipos que solo cubren diagnóstico).', 'keywords' => '["diagnosticaron", "cáncer", "mama", "estoy", "potestativo", "hace", "meses", "cubre"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Tuve COVID-19 y estuve internado 15 días. Mi seguro potestativo lo contraté hace 4 meses. ¿Me cubren la hospitalización?', 'answer' => 'Sí, porque ya cumpliste los 3 meses de período de carencia. El COVID-19 no tiene período de espera especial más allá de la carencia general. La hospitalización por enfermedad está cubierta. Debes presentar los documentos médicos (epicrisis, indicaciones, etc.).', 'keywords' => '["tuve", "covid", "estuve", "internado", "días", "seguro", "potestativo", "contraté"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => 'No pagué mi potestativo por 2 meses seguidos. ¿Perdí el seguro para siempre? ¿Puedo recuperarlo?', 'answer' => 'Perdiste el seguro por resolución automática del contrato (2 meses consecutivos de impago). Puedes volver a afiliarte, pero tendrías que reiniciar el período de carencia (3 meses) y todos los períodos de espera desde cero. No hay "rehabilitación" después de 2 meses; solo aplica rehabilitación si fue menos de 2 meses.', 'keywords' => '["pagué", "potestativo", "meses", "seguidos", "perdí", "seguro", "siempre", "puedo"]'],
            ['category_name' => 'Afiliaciones', 'question' => 'Estuve en seguro regular 2 años, me despidieron, me quedan 4 meses de latencia. ¿Puedo cambiarme al potestativo sin perder cobertura? ¿Se respetan mis períodos de espera ya cumplidos?', 'answer' => 'Sí, puedes afiliarte al potestativo antes de que termine tu latencia. Si lo haces dentro de los 30 días siguientes al cese o antes de culminar la latencia, aplica continuidad de cobertura. Esto significa que NO tienes que cumplir nuevamente el período de carencia (3 meses) y se respetan los períodos de espera que ya habías cumplido en el seguro regular.', 'keywords' => '["estuve", "seguro", "regular", "años", "despidieron", "quedan", "meses", "latencia"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Tengo VIH, estoy en potestativo desde hace 6 meses. El PEAS dice que el período de espera es 10 meses. ¿Me cubren mi tratamiento antirretroviral?', 'answer' => 'No, aún no. Con 6 meses no cumples los 10 meses de período de espera para VIH. Debes seguir pagando 4 meses más para tener cobertura de tratamiento. El PEAS redujo el período de 24 a 10 meses, pero no lo eliminó. Mientras tanto, puedes acceder a tratamiento gratuito en el Ministerio de Salud (MINSA) a través del sistema público.', 'keywords' => '["tengo", "estoy", "potestativo", "hace", "meses", "peas", "dice", "período"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => 'Mi hijo tiene una enfermedad congénita diagnosticada al nacer. Lo afilié al potestativo a los 3 días de nacido. ¿Qué período de espera aplica?', 'answer' => 'Los recién nacidos afiliados dentro de los primeros 30 días de nacimiento están exentos del período de carencia (3 meses) si el titular está al día en sus aportes. Sin embargo, para enfermedades congénitas, el período de espera es de 10 meses (reducido de 24 por PEAS). El tratamiento de la enfermedad congénita solo estará cubierto después de 10 meses de aportes continuos.', 'keywords' => '["hijo", "tiene", "enfermedad", "congénita", "diagnosticada", "nacer", "afilié", "potestativo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El SCTR cubre accidentes en el trayecto de mi casa al trabajo?', 'answer' => 'No. La cobertura del SCTR es estrictamente operacional: solo cubre accidentes que ocurren mientras ejecutas las funciones de tu puesto de trabajo de alto riesgo. Quedan excluidos los accidentes en el trayecto (ida y vuelta al trabajo).', 'keywords' => '["sctr", "cubre", "accidentes", "trayecto", "casa", "trabajo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Si trabajo desde casa (home office), necesito SCTR?', 'answer' => 'Depende de tu actividad. Si tu trabajo desde casa sigue siendo una actividad de alto riesgo según el Anexo 5 (ejemplo: manejo de sustancias peligrosas, manufactura), probablemente sí. Si es administrativo desde casa, tu empleador probablemente no está obligado a afiliarte al SCTR. Consulta tu CIIU.', 'keywords' => '["trabajo", "casa", "home", "office", "necesito", "sctr"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El SCTR cubre enfermedades profesionales como silicosis?', 'answer' => 'Sí, el SCTR cubre enfermedades profesionales listadas en la Resolución Ministerial N° 480-2008/MINSA, que incluye silicosis, neumoconiosis, hipoacusia inducida por ruido, intoxicaciones crónicas, entre otras.', 'keywords' => '["sctr", "cubre", "enfermedades", "profesionales", "silicosis"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo tener SCTR si soy independiente y trabajo en minería?', 'answer' => 'Sí. Los trabajadores independientes que realizan actividades de alto riesgo pueden afiliarse al SCTR mediante el Formulario 6004, presentado presencialmente en una OSPE. Necesitas RUC vigente y pagar aportes mensuales en el Banco de la Nación.', 'keywords' => '["puedo", "tener", "sctr", "independiente", "trabajo", "minería"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿El SCTR cubre consultas psicológicas después de un accidente laboral?', 'answer' => 'Sí, la cobertura incluye rehabilitación y readaptación laboral integral, que puede incluir apoyo psicológico como parte del proceso de recuperación tras un accidente laboral que haya afectado la salud mental del trabajador.', 'keywords' => '["sctr", "cubre", "consultas", "psicológicas", "después", "accidente", "laboral"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Trabajo en construcción (Nivel III). Mi empleador no me ha afiliado al SCTR. Sufrí un accidente laboral. ¿Quién paga mis gastos médicos?', 'answer' => 'Tu empleador es responsable por no cumplir con su obligación legal de afiliarte al SCTR. Debe pagar tus gastos médicos directamente. EsSalud te atenderá igual, pero luego le cobrará todos los gastos a tu empleador. Además, tu empleador puede ser multado por SUNAFIL.', 'keywords' => '["trabajo", "construcción", "nivel", "empleador", "afiliado", "sctr", "sufrí", "accidente"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Soy independiente, tengo SCTR, tuve un accidente laboral. No presenté el Aviso de Accidente de Trabajo hasta el día 6. ¿Me cubren?', 'answer' => 'El plazo para regularizar el Aviso de Accidente de Trabajo es de 5 días hábiles siguientes al accidente. Si lo presentaste al día 6 (hábiles), excediste el plazo. Es probable que la cobertura sea rechazada. Presenta igual el aviso y apela, explicando la demora, pero no hay garantía de cobertura.', 'keywords' => '["independiente", "tengo", "sctr", "tuve", "accidente", "laboral", "presenté", "aviso"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Trabajo en minería (Nivel IV). ¿Cuánto debo pagar de SCTR si mi sueldo es S/ 3,000? ¿Y si fuera independiente?', 'answer' => 'Si eres dependiente: S/ 3,000 × 1.83% = S/ 54.90 mensual (lo paga tu empleador). Si eres independiente: con UIT 2026 (S/ 5,500), ½ UIT = S/ 2,750 × 1.83% = S/ 50.33 mensual (lo pagas tú). La diferencia se debe a que la base de cálculo es diferente.', 'keywords' => '["trabajo", "minería", "nivel", "cuánto", "debo", "pagar", "sctr", "sueldo"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Tuve un accidente laboral cubierto por SCTR. ¿Puedo cobrar también el subsidio por incapacidad temporal de EsSalud?', 'answer' => 'No. El SCTR ya cubre la atención médica al 100% y las pensiones por invalidez. El subsidio por ITT del seguro regular de EsSalud es para enfermedades o accidentes NO laborales. Al ser un accidente laboral cubierto por SCTR, no corresponde cobrar ITT de EsSalud. Hay exclusión expresa para evitar duplicidad.', 'keywords' => '["tuve", "accidente", "laboral", "cubierto", "sctr", "puedo", "cobrar", "también"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Trabajo en una empresa de transporte (Nivel II). Tuve un accidente de tránsito mientras trabajaba (manejando el camión). Mi empleador tiene SCTR. Además, el accidente fue por culpa de otro conductor. ¿Qué seguros me cubren?', 'answer' => 'Primero cubre el SOAT del vehículo culpable. Lo que no cubra el SOAT, lo cubre el SCTR de tu empleador. No puedes cobrar doble. Debes denunciar el accidente a la policía y hacerte el dosaje etílico dentro de las 4 horas para validar que no estabas bajo efectos del alcohol. El SCTR cubre toda tu atención médica, rehabilitación y prótesis si fueran necesarias.', 'keywords' => '["trabajo", "empresa", "transporte", "nivel", "tuve", "accidente", "tránsito", "mientras"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Soy trabajador independiente con SCTR (minería). Tuve un accidente laboral que me dejó con incapacidad permanente parcial. ¿Qué beneficios tengo?', 'answer' => 'El SCTR cubre: atención médica completa hasta tu recuperación máxima, rehabilitación física y readaptación laboral, prótesis o dispositivos ortopédicos necesarios. Además, la póliza puede otorgarte una indemnización según el porcentaje de invalidez (ejemplo: 20% de invalidez = 20% de la indemnización pactada). El monto exacto depende de la póliza contratada.', 'keywords' => '["trabajador", "independiente", "sctr", "minería", "tuve", "accidente", "laboral", "dejó"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿La latencia cubre a mis hijos también o solo a mí?', 'answer' => 'La latencia cubre al asegurado titular y a todos sus derechohabientes registrados (cónyuge, hijos, etc.). Los familiares mantienen la misma cobertura que el titular durante el período de latencia.', 'keywords' => '["latencia", "cubre", "hijos", "también", "solo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Si renuncio a mi trabajo, tengo derecho a latencia?', 'answer' => 'Sí, la latencia aplica para cualquier cese laboral, sea por renuncia, despido o fin de contrato. Lo importante es que tengas al menos 5 meses de aportes en los últimos 3 años.', 'keywords' => '["renuncio", "trabajo", "tengo", "derecho", "latencia"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Puedo sacar citas programadas durante la latencia?', 'answer' => 'Sí, durante la latencia puedes acceder a atenciones médicas programadas (citas) dentro de la cobertura que corresponda según la tabla de latencia. Los primeros meses cubren PEAS + exceso; los últimos meses solo exceso y maternidad.', 'keywords' => '["puedo", "sacar", "citas", "programadas", "durante", "latencia"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿La latencia cubre emergencias por accidente desde el día 1?', 'answer' => 'Sí, la latencia cubre emergencias desde el primer día, como cualquier asegurado regular. No hay período de carencia adicional. Si sufres un accidente durante tu latencia, serás atendido.', 'keywords' => '["latencia", "cubre", "emergencias", "accidente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Si encuentro trabajo durante mi latencia, pierdo los meses restantes?', 'answer' => 'No los "pierdes" como algo negativo. Simplemente tu nuevo empleador te afilia al Seguro Regular y tu cobertura de latencia se reemplaza por la cobertura del nuevo trabajo. No hay penalidad ni tienes que "devolver" nada.', 'keywords' => '["encuentro", "trabajo", "durante", "latencia", "pierdo", "meses", "restantes"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Trabajé 2 años seguidos, luego me despidieron. ¿Cuántos meses de latencia me corresponden? ¿Cubren todas las atenciones?', 'answer' => 'Con 24 meses de aportes (20-24 meses en la tabla), te corresponden 8 meses de latencia. Los primeros 4 meses cubren PEAS + exceso (cobertura completa). Los siguientes 4 meses cubren solo exceso al PEAS y maternidad (cobertura limitada).', 'keywords' => '["trabajé", "años", "seguidos", "luego", "despidieron", "cuántos", "meses", "latencia"]'],
            ['category_name' => 'Afiliaciones', 'question' => 'Terminó mi latencia de 6 meses. No conseguí trabajo. ¿Puedo afiliarme al potestativo sin perder continuidad? ¿Qué pasa con mis períodos de espera?', 'answer' => 'Sí, puedes afiliarte al potestativo. Si lo haces antes de que termine la latencia, aplica continuidad de cobertura: no tendrás período de carencia (3 meses) y se respetarán los períodos de espera ya cumplidos (ejemplo: si ya tenías 8 meses de aporte para cáncer, solo necesitas 2 más). Si lo haces después de que terminó la latencia, empiezas desde cero.', 'keywords' => '["terminó", "latencia", "meses", "conseguí", "trabajo", "puedo", "afiliarme", "potestativo"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Mi empleador no declaró mi cese en SUNAT. ¿Cómo activo mi latencia? ¿Puedo hacerlo yo mismo?', 'answer' => 'Tu latencia depende de que tu empleador declare tu cese. Si no lo hizo, el sistema de EsSalud no sabe que dejaste de trabajar. Puedes acudir a una OSPE con tu DNI y tus boletas de pago para solicitar la activación manual de tu latencia. También puedes reclamar a tu empleador para que registre el cese.', 'keywords' => '["empleador", "declaró", "cese", "sunat", "cómo", "activo", "latencia", "puedo"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Puedo inscribir a mi suegra como derechohabiente?', 'answer' => 'No. Los derechohabientes son: cónyuge o concubino(a), hijos menores de edad, hijos mayores incapacitados, y madre gestante de hijo extramatrimonial. Los suegros no están incluidos en la lista.', 'keywords' => '["puedo", "inscribir", "suegra", "derechohabiente"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Mis hijos adoptivos tienen los mismos derechos que mis hijos biológicos?', 'answer' => 'Sí. Los hijos adoptivos tienen los mismos derechos como derechohabientes. Debes presentar la resolución judicial de adopción o el acta de nacimiento que acredite la adopción.', 'keywords' => '["hijos", "adoptivos", "tienen", "mismos", "derechos", "biológicos"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Puedo inscribir a mi conviviente si vivimos juntos pero no tenemos documento de unión de hecho?', 'answer' => 'No. EsSalud exige documento oficial de reconocimiento de unión de hecho, ya sea por Resolución Judicial o por Escritura Pública notarial inscrita en SUNARP. No acepta declaraciones simples de convivencia.', 'keywords' => '["puedo", "inscribir", "conviviente", "vivimos", "juntos", "tenemos", "documento", "unión"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Si me divorcio, mi ex cónyuge sigue siendo derechohabiente?', 'answer' => 'No. Al divorciarse, el ex cónyuge pierde automáticamente la condición de derechohabiente. Debes solicitar su baja en EsSalud (Formulario 1010) presentando la resolución judicial de divorcio. Si no lo haces, estarías cometiendo una irregularidad.', 'keywords' => '["divorcio", "cónyuge", "sigue", "siendo", "derechohabiente"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Puedo tener a mis padres como derechohabientes?', 'answer' => 'No, en el Seguro Regular y Potestativo los padres no son derechohabientes. Solo aplica para ciertos regímenes especiales o para el orden de prelación en sepelio. Los padres pueden ser beneficiarios en el seguro +Vida si los designas.', 'keywords' => '["puedo", "tener", "padres", "derechohabientes"]'],
            ['category_name' => 'Afiliaciones', 'question' => 'Mi hijo cumple 18 años en 3 días. Tiene parálisis cerebral diagnosticada. ¿Qué debo hacer para que no pierda la cobertura?', 'answer' => 'Debes solicitar el Dictamen Médico de Incapacidad para tu hijo. El plazo límite es dentro de los 30 días previos a que cumpla 18 años. Con ese dictamen, tu hijo mantiene la condición de derechohabiente después de los 18. Si no lo haces a tiempo, perderá la cobertura y tendrás que reiniciar el trámite.', 'keywords' => '["hijo", "cumple", "años", "días", "tiene", "parálisis", "cerebral", "diagnosticada"]'],
            ['category_name' => 'Afiliaciones', 'question' => 'Mi esposa es extranjera, nos casamos en su país. ¿Qué documentos necesito para inscribirla como derechohabiente?', 'answer' => 'Necesitas: Formulario 1010, DNI de ambos, y acta de matrimonio extranjera legalizada por el consulado peruano en ese país o con sello de Apostilla de La Haya. Si el acta está en otro idioma, debe venir con traducción oficial al español.', 'keywords' => '["esposa", "extranjera", "casamos", "país", "documentos", "necesito", "inscribirla", "derechohabiente"]'],
            ['category_name' => 'Afiliaciones', 'question' => 'Inscribí a mi concubina como derechohabiente hace 2 años. Terminamos la relación. ¿Cómo la doy de baja? ¿Necesito un documento legal?', 'answer' => 'Puedes darle de baja mediante una Declaración Jurada en el Formulario 1010, indicando el cese de la unión de hecho. No necesitas documento legal adicional, pero la declaración tiene carácter de juramento. Si declaras falsamente, puedes ser denunciado penalmente. Si ella no está de acuerdo, puede reclamar.', 'keywords' => '["inscribí", "concubina", "derechohabiente", "hace", "años", "terminamos", "relación", "cómo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo usar VIVA desde mi celular o solo desde computadora?', 'answer' => 'Puedes usar VIVA desde el navegador de tu celular. No es necesario tener una app específica; solo abre el navegador (Chrome, Safari, etc.) y entra a viva.essalud.gob.pe. La plataforma es responsive y se adapta a pantallas móviles.', 'keywords' => '["puedo", "usar", "viva", "celular", "solo", "computadora"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿VIVA funciona los fines de semana?', 'answer' => 'Sí, la plataforma VIVA está disponible 24/7, los 365 días del año. Puedes iniciar trámites, adjuntar documentos y consultar el estado de tus solicitudes cualquier día, incluso fines de semana y feriados.', 'keywords' => '["viva", "funciona", "fines", "semana"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Puedo hacer el trámite de latencia por VIVA o es solo presencial?', 'answer' => 'El trámite de latencia es presencial en una OSPE. No se puede hacer por VIVA. Debes acudir a la oficina con tu DNI para solicitar la activación de tu cobertura por desempleo.', 'keywords' => '["puedo", "hacer", "trámite", "latencia", "viva", "solo", "presencial"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Mi Consulta muestra mis resultados de COVID-19?', 'answer' => 'Sí, si te realizaste la prueba de COVID-19 en un centro de EsSalud, los resultados aparecen en Mi Consulta, en la sección "Exámenes de Laboratorio" o "Ayuda al Diagnóstico".', 'keywords' => '["consulta", "muestra", "resultados", "covid"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Puedo pedir mi CITT por VIVA si mi descanso fue de un médico particular?', 'answer' => 'Sí, pero no es automático. Debes subir tu certificado médico particular a VIVA para que sea validado. El proceso de validación es el que genera el CITT oficial. Una vez validado, puedes descargar tu CITT desde VIVA.', 'keywords' => '["puedo", "pedir", "citt", "viva", "descanso", "médico", "particular"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Subí mi certificado médico particular a VIVA para validación, pero pasaron 5 días y no tengo respuesta. ¿Qué hago? ¿Cuánto tiempo tienen para responder?', 'answer' => 'El plazo máximo para validación de certificados médicos es de 3 días hábiles. Si pasaron 5 días, puedes: 1) Revisar el estado de tu trámite en VIVA, 2) Comunicarte con la central de EsSalud (411-8000), 3) Acudir a una OSPE para consultar. Si no hay respuesta, puedes considerar que aplica silencio administrativo para efectos de apelación.', 'keywords' => '["subí", "certificado", "médico", "particular", "viva", "validación", "pasaron", "días"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Intenté adjuntar un PDF en VIVA pero el sistema dice "archivo no válido". Mi archivo pesa 3MB. ¿Qué puede estar pasando?', 'answer' => 'Posibles causas: 1) El nombre del archivo tiene caracteres especiales (ñ, tildes, comas, espacios). Renómbralo a algo simple como "documento.pdf". 2) El archivo no es realmente PDF (aunque la extensión lo diga). 3) El PDF está protegido o encriptado. 4) El navegador no es compatible (prueba con Chrome en modo incógnito). El peso de 3MB está dentro del límite de 5MB.', 'keywords' => '["intenté", "adjuntar", "viva", "sistema", "dice", "archivo", "válido", "pesa"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => 'Me registré en VIVA pero nunca me llegó el correo de activación. Revisé spam y nada. ¿Qué hago?', 'answer' => 'Espera al menos 24 horas. Si aún no llega, verifica que escribiste bien tu correo. Puedes intentar registrarte nuevamente. Si el sistema dice que tu DNI ya está registrado, solicita reenvío de activación. Si nada funciona, reporta la incidencia a atencionalasegurado@essalud.gob.pe o acude a una OSPE para que limpien tu registro.', 'keywords' => '["registré", "viva", "nunca", "llegó", "correo", "activación", "revisé", "spam"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Fui al hospital y me dijeron que no estoy afiliado, pero mi empleador me descuenta EsSalud de mi sueldo. ¿Qué hago?', 'answer' => 'Primero, pide a tu empleador el comprobante de pago de aportes. Luego acude a una OSPE con tu DNI y tus boletas de pago para que te activen manualmente. EsSalud atenderá tu emergencia igualmente, pero debes regularizar. También puedes denunciar a tu empleador si persiste el problema.', 'keywords' => '["hospital", "dijeron", "estoy", "afiliado", "empleador", "descuenta", "essalud", "sueldo"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Mi empleador no me quiere pagar los primeros 20 días de mi descanso. ¿A dónde puedo denunciar?', 'answer' => 'Puedes denunciar a tu empleador en SUNAFIL (Superintendencia Nacional de Fiscalización Laboral). También puedes pedir a EsSalud que te pague directamente desde el día 1 y luego EsSalud le cobrará a tu empleador. Guarda todos los comprobantes de tu descanso médico (CITT).', 'keywords' => '["empleador", "quiere", "pagar", "primeros", "días", "descanso", "dónde", "puedo"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Pasé 3 horas en la fila de EsSalud para sacar una cita. ¿Hay otra forma más rápida?', 'answer' => 'Sí, usa los canales digitales: 1) App Mi Consulta (descárgala gratuitamente), 2) Portal web Mi Consulta (miconsulta.essalud.gob.pe), 3) EsSalud en Línea vía telefónica. Estos canales evitan las filas presenciales.', 'keywords' => '["pasé", "horas", "fila", "essalud", "sacar", "cita", "otra", "forma"]'],
            ['category_name' => 'Consultas Médicas', 'question' => 'Me robaron mi cartera con mi DNI y mi carnet EsSalud. ¿Cómo me atiendo si necesito emergencia?', 'answer' => 'En emergencia, acude al hospital. Explica tu situación. Si tienes una copia digital o foto de tu DNI, muéstrala. El hospital puede verificar tu afiliación con tu nombre y fecha de nacimiento. Luego, tramita un duplicado de tu DNI en RENIEC para futuras atenciones.', 'keywords' => '["robaron", "cartera", "carnet", "essalud", "cómo", "atiendo", "necesito", "emergencia"]'],
            ['category_name' => 'Consultas Generales', 'question' => 'Mi empleador me descontó el 9% de EsSalud de mi sueldo diciendo que es mi parte. ¿Es legal?', 'answer' => 'No es legal. El aporte del 9% para EsSalud es de cargo exclusivo del empleador. Está prohibido descontarlo al trabajador. Puedes reclamar a tu empleador y, si persiste, denunciar ante SUNAFIL.', 'keywords' => '["empleador", "descontó", "essalud", "sueldo", "diciendo", "parte", "legal"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Mi empleador me pagó los primeros 20 días de incapacidad, pero cuando solicitó el reembolso a EsSalud, se lo rechazaron porque tiene deudas. ¿Qué pasa con mi subsidio? ¿Me lo quitan?', 'answer' => 'No te lo quitan. El problema es entre tu empleador y EsSalud. Tú ya recibiste tu pago. Si EsSalud rechazó el reembolso, tu empleador asume la pérdida. No pueden descontarte ni cobrarte después. Sin embargo, para futuros subsidios, tu empleador podría negarse a pagar. Evalúa si es momento de cambiar de trabajo.', 'keywords' => '["empleador", "pagó", "primeros", "días", "incapacidad", "solicitó", "reembolso", "essalud"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Fui al banco a cobrar mi subsidio de lactancia, pero el banco dice que no hay depósito. En VIVA dice "Conforme". ¿Qué hago?', 'answer' => 'Espera 2 o 3 días hábiles desde que viste "Conforme". A veces el banco tarda en reflejar el depósito. Si pasó más de 1 semana, verifica si ya pasaron 20 días hábiles desde la fecha de pago. Si pasaron, el dinero pudo haber regresado a EsSalud y debes solicitar rehabilitación de pago en una OSPE.', 'keywords' => '["banco", "cobrar", "subsidio", "lactancia", "dice", "depósito", "viva", "conforme"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => 'Solicité mi subsidio hace 2 meses, sigue en "Evaluación". Ya pasaron los 15 días hábiles. ¿Qué puedo hacer?', 'answer' => 'El plazo máximo es 15 días hábiles. Si ya pasó, aplica silencio administrativo negativo (se considera denegado). Puedes presentar un recurso de apelación ante la instancia superior de EsSalud. También puedes acudir a una OSPE para consultar el estado y pedir una respuesta inmediata.', 'keywords' => '["solicité", "subsidio", "hace", "meses", "sigue", "evaluación", "pasaron", "días"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué diferencia hay entre el seguro potestativo y el seguro regular en cuanto a cobertura?', 'answer' => 'El seguro regular cubre más prestaciones que el potestativo. El potestativo tiene exclusiones específicas (no cubre diálisis, trasplantes, enfermedades raras, accidentes de trabajo) y períodos de espera más largos (24 meses para algunas condiciones). El seguro regular cubre todo con solo los aportes mínimos (3 meses consecutivos). El potestativo es voluntario y lo pagas tú; el regular lo paga tu empleador.', 'keywords' => '["diferencia", "seguro", "potestativo", "regular", "cuanto", "cobertura"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Es mejor el seguro agrario o el potestativo para un agricultor independiente?', 'answer' => 'Para un agricultor independiente, el seguro agrario es mejor porque tiene tasas de aporte preferenciales (6% en 2026 vs 9% del regular) y requisitos más flexibles (puede aportar sobre RMV). El potestativo tiene costos fijos por edad (S/ 132 a S/ 215). Además, el seguro agrario no tiene límite de edad ni exclusión por actividades rurales.', 'keywords' => '["mejor", "seguro", "agrario", "potestativo", "agricultor", "independiente"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué conviene más: contratar SCTR por EsSalud o con una aseguradora privada?', 'answer' => 'EsSalud SCTR tiene la ventaja de integración con la red de EsSalud (sin copagos). Los seguros privados (Rímac, Pacífico, etc.) suelen tener mejores tiempos de atención y clínicas de mayor nivel, pero pueden tener copagos y deducibles. La decisión depende de tu presupuesto y de las exigencias de tu empleador. Ambas son válidas.', 'keywords' => '["conviene", "contratar", "sctr", "essalud", "aseguradora", "privada"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Diferencia entre subsidio por ITT y pensión de invalidez?', 'answer' => 'El subsidio por ITT es temporal (máx. 11 meses y 10 días) y se paga mientras te recuperas de una enfermedad o accidente no laboral. La pensión de invalidez es permanente y se otorga cuando una comisión médica determina que tu incapacidad es total y permanente para el trabajo (no hay recuperación esperada). La pensión es de por vida o hasta que revierta la condición.', 'keywords' => '["diferencia", "subsidio", "pensión", "invalidez"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Cómo puedo comunicarme con un asesor de EsSalud por teléfono?', 'answer' => 'Llama a EsSalud en Línea. Lima/Callao: 411-8000. Provincias: cada región tiene su número. También puedes llamar a la central 350-0800 (opción 2 para Lima y Callao). Las llamadas no son gratuitas, tienen costo local.', 'keywords' => '["cómo", "puedo", "comunicarme", "asesor", "essalud", "teléfono"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si no entiendo una respuesta de EsSalud o creo que está mal?', 'answer' => 'Puedes solicitar una aclaración por escrito en la misma OSPE donde realizaste el trámite. Si no estás conforme, puedes presentar un recurso de apelación (dentro del plazo legal), acudir a la Defensoría del Pueblo o presentar un reclamo ante SUSALUD (Superintendencia Nacional de Salud).', 'keywords' => '["hago", "entiendo", "respuesta", "essalud", "creo", "está"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Dónde puedo presentar una queja formal contra EsSalud?', 'answer' => 'Puedes presentar una queja en: 1) El Libro de Reclamaciones de EsSalud (presencial o virtual en su portal web), 2) SUSALUD (Superintendencia Nacional de Salud), 3) La Defensoría del Pueblo, 4) Indecopi si es un tema de protección al consumidor.', 'keywords' => '["dónde", "puedo", "presentar", "queja", "formal", "contra", "essalud"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Existe un correo electrónico para consultas rápidas?', 'answer' => 'Sí, puedes escribir a atencionalasegurado@essalud.gob.pe para consultas generales. Para problemas con plataformas digitales, puedes usar ese mismo correo adjuntando capturas de pantalla del error. Para temas específicos de prestaciones económicas, consulta con tu OSPE local.', 'keywords' => '["existe", "correo", "electrónico", "consultas", "rápidas"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo pedir que me atienda un abogado especializado en EsSalud?', 'answer' => 'EsSalud no proporciona abogados gratuitos para asesoría personal. Sin embargo, puedes consultar con un abogado privado especializado en seguridad social. También puedes acudir a consultorios jurídicos gratuitos de universidades o a la Defensoría del Pueblo si el caso es de vulneración de derechos.', 'keywords' => '["puedo", "pedir", "atienda", "abogado", "especializado", "essalud"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cuánto es el subsidio por lactancia?', 'answer' => 'El monto es de S/ 820.00 por cada hijo nacido vivo. En caso de parto múltiple (mellizos, trillizos), se recibe un subsidio por cada recién nacido.', 'keywords' => '["cuánto", "subsidio", "lactancia"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cómo cobro el subsidio por lactancia?', 'answer' => 'Si diste a luz en un hospital de EsSalud, el pago es automático ("Cero Trámite") y te depositan sin que hagas nada. Si fue en clínica particular, debes presentar el Formulario 1040 en EsSalud o por la plataforma VIVA.', 'keywords' => '["cómo", "cobro", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cómo sé si mi subsidio por lactancia será por el sistema "Cero Trámite"?', 'answer' => 'Si tu parto fue en un hospital o clínica de EsSalud, ellos registran el nacimiento y el subsidio se activa solo. Si fue en clínica particular que no es de EsSalud, debes hacer el trámite tú misma.', 'keywords' => '["cómo", "subsidio", "lactancia", "será", "sistema", "cero", "trámite"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Necesito presentar algún formulario en el banco para cobrar el subsidio por lactancia?', 'answer' => 'No. El banco solo te pide tu DNI. Si tienes cuenta a tu nombre, depositan allí; si no, te dan el dinero en ventanilla con tu DNI.', 'keywords' => '["necesito", "presentar", "algún", "formulario", "banco", "cobrar", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Qué hago si mi parto fue en una clínica particular, puedo recibir el subsidio por lactancia?', 'answer' => 'Sí. Debes presentar el Formulario 1040, el acta de nacimiento de tu bebé, tu DNI y el certificado de nacido vivo en la plataforma VIVA o en una oficina de EsSalud.', 'keywords' => '["hago", "parto", "clínica", "particular", "puedo", "recibir", "subsidio", "lactancia"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuánto tiempo tengo para cobrar mi subsidio de lactancia?', 'answer' => 'Tienes 6 meses desde que terminó tu descanso post parto. Por ejemplo, si tu bebé nació el 1 de enero y tu descanso terminó el 31 de marzo, tienes hasta el 30 de septiembre para cobrar.', 'keywords' => '["cuánto", "tiempo", "tengo", "cobrar", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Tuve mellizos, recibo un solo subsidio de lactancia?', 'answer' => 'No. Recibes un subsidio por cada hijo. Si tuviste mellizos, son dos pagos de S/ 820 cada uno (S/ 1,640 en total). Si fueron trillizos, serían tres pagos.', 'keywords' => '["tuve", "mellizos", "recibo", "solo", "subsidio", "lactancia"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Puedo pedir el subsidio de lactancia si el bebé falleció poco después de nacer?', 'answer' => 'Sí. El subsidio es por el nacimiento vivo, no porque el bebé siga vivo después. Necesitas el acta de nacimiento y, si falleció, también el acta de defunción.', 'keywords' => '["puedo", "pedir", "subsidio", "lactancia", "bebé", "falleció", "poco", "después"]'],
            ['category_name' => 'Subsidio por Lactancia', 'question' => '¿Cómo funciona el pago de lactancia "Cero Trámites" si doy a luz en un hospital de EsSalud?', 'answer' => 'Es automático. Cuando das a luz, ellos registran el nacimiento en su sistema. Esa información llega al área de prestaciones económicas y activan el pago sin que tú hagas nada. En unos días te depositan los S/ 820.', 'keywords' => '["cómo", "funciona", "pago", "lactancia", "cero", "trámites", "hospital", "essalud"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Quién debe cobrar el subsidio de lactancia si la madre es menor de edad y soltera?', 'answer' => 'El subsidio lo puede cobrar su padre, madre o tutor del bebé (los abuelos o el adulto responsable). Ellos deben presentar su DNI y acreditar que tienen al bebé a su cargo.', 'keywords' => '["quién", "debe", "cobrar", "subsidio", "lactancia", "madre", "menor", "edad"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Cuáles son los requisitos para solicitar el subsidio por maternidad?', 'answer' => '1) Haber estado afiliada a EsSalud en el momento de la concepción. 2) Tener 3 meses de aportes seguidos o 4 no seguidos en los últimos 6 meses antes de tu descanso. 3) Tener vínculo laboral activo al momento del parto.', 'keywords' => '["cuáles", "requisitos", "solicitar", "subsidio", "maternidad"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Cuánto tiempo tengo para solicitar el subsidio por maternidad?', 'answer' => 'Tienes 6 meses desde que termina tu descanso post parto (los 90 o 98 días). Si pasas ese tiempo, pierdes el derecho.', 'keywords' => '["cuánto", "tiempo", "tengo", "solicitar", "subsidio", "maternidad"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Cómo se paga el subsidio por maternidad?', 'answer' => 'Depende: Si eres trabajadora dependiente, tu empleador te paga y luego él le pide a EsSalud que le devuelva la plata. Si eres independiente (trabajadora del hogar, pescadora, etc.), EsSalud te paga directamente en tu cuenta o en ventanilla del banco.', 'keywords' => '["cómo", "paga", "subsidio", "maternidad"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Puedo pedir mi subsidio de maternidad antes de que termine mi descanso?', 'answer' => 'Sí. Puedes presentar tu solicitud antes, pero el pago se empieza a contar desde que empezó tu descanso. Es mejor presentarlo apenas tengas todos los papeles.', 'keywords' => '["puedo", "pedir", "subsidio", "maternidad", "antes", "termine", "descanso"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Cuál es el plazo máximo para solicitar el reembolso por maternidad?', 'answer' => 'El empleador tiene 6 meses desde que terminó el período de descanso de la trabajadora (los 90 o 98 días) para pedir el reembolso a EsSalud.', 'keywords' => '["cuál", "plazo", "máximo", "solicitar", "reembolso", "maternidad"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué es el subsidio por ITT?', 'answer' => 'ITT significa "Incapacidad Temporal para el Trabajo". Es el dinero que recibes cuando te enfermas o te accidentas y no puedes trabajar por varios días. Es como un "seguro" que te paga un sueldo mientras te recuperas.', 'keywords' => '["subsidio"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cómo solicito el subsidio por incapacidad temporal?', 'answer' => 'Primero, tu médico te da un CITT. Si es de EsSalud, ya está listo. Si es particular, primero debes validarlo. Luego, llenas el Formulario 1040 y lo presentas en EsSalud (por VIVA o presencial).', 'keywords' => '["cómo", "solicito", "subsidio", "incapacidad", "temporal"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿A partir de qué día EsSalud asume el pago por incapacidad temporal?', 'answer' => 'EsSalud empieza a pagar recién a partir del día 21 de tu incapacidad. Los primeros 20 días los paga tu empleador con tu sueldo normal.', 'keywords' => '["partir", "essalud", "asume", "pago", "incapacidad", "temporal"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuánto dura el subsidio por incapacidad temporal como máximo?', 'answer' => 'El tiempo máximo que puedes recibir este subsidio por una misma enfermedad o accidente es de 11 meses y 10 días seguidos.', 'keywords' => '["cuánto", "dura", "subsidio", "incapacidad", "temporal", "máximo"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué pasa si presento mi solicitud de subsidio después de los 6 meses?', 'answer' => 'Pierdes el derecho al subsidio. Tienes 6 meses desde que terminó tu incapacidad. Por ejemplo, si te recuperaste el 31 de marzo, tienes hasta el 30 de septiembre para presentar tu solicitud.', 'keywords' => '["pasa", "presento", "solicitud", "subsidio", "después", "meses"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Quién es el responsable de tramitar el subsidio de una trabajadora del hogar?', 'answer' => 'La propia trabajadora del hogar. Ella debe hacer el trámite directamente en EsSalud (pago directo). Su empleador no está obligado a hacer el reembolso.', 'keywords' => '["quién", "responsable", "tramitar", "subsidio", "trabajadora", "hogar"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuál es la obligación del empleador respecto al pago del subsidio para un trabajador dependiente?', 'answer' => 'El empleador debe pagar los primeros 20 días de incapacidad. Si el trabajador sigue enfermo, el empleador sigue pagando por cuenta de EsSalud (y luego pide el reembolso). También debe declarar correctamente las incapacidades en la planilla electrónica.', 'keywords' => '["cuál", "obligación", "empleador", "respecto", "pago", "subsidio", "trabajador", "dependiente"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Cómo solicito el reembolso por sepelio y cuál es el monto máximo?', 'answer' => 'Llenas el Formulario 1040 (sección de sepelio), adjuntas el acta de defunción, los comprobantes de gastos funerarios a tu nombre, y tu DNI. Lo presentas en EsSalud (VIVA o presencial). El monto máximo es S/ 2,070.', 'keywords' => '["cómo", "solicito", "reembolso", "sepelio", "cuál", "monto", "máximo"]'],
            ['category_name' => 'Subsidio por Sepelio', 'question' => '¿Qué gastos funerarios cubre la prestación por sepelio?', 'answer' => 'Cubren gastos básicos: ataúd, nicho o sepultura, cremación, capilla ardiente, carroza fúnebre, transporte del cuerpo, mortaja y preparación del cadáver. NO cubren flores, esquelas, lápidas lujosas ni gastos de lujo.', 'keywords' => '["gastos", "funerarios", "cubre", "prestación", "sepelio"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Cuál es el plazo máximo para solicitar el subsidio por sepelio?', 'answer' => 'Tienes 6 meses desde la fecha del fallecimiento de tu familiar. Si pasas ese tiempo, pierdes el derecho al reembolso.', 'keywords' => '["cuál", "plazo", "máximo", "solicitar", "subsidio", "sepelio"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Quiénes tienen derecho a cobrar el subsidio por sepelio?', 'answer' => 'En este orden: 1° cónyuge o concubino del fallecido, 2° hijos, 3° padres, 4° hermanos. Si no hay ninguno, cualquier tercero que demuestre con facturas que pagó el entierro.', 'keywords' => '["quiénes", "tienen", "derecho", "cobrar", "subsidio", "sepelio"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué hago si fui al banco a cobrar mi subsidio y me dicen que el depósito no está disponible?', 'answer' => 'Pueden pasar dos cosas: 1) Aún no ha llegado la orden de pago al banco (espera 2 o 3 días). 2) El dinero ya regresó a EsSalud porque pasaron más de 20 días hábiles. Si es lo segundo, pide rehabilitación de pago en EsSalud.', 'keywords' => '["hago", "banco", "cobrar", "subsidio", "dicen", "depósito", "está", "disponible"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuántos días tengo para cobrar un subsidio en el banco antes de que el dinero regrese a EsSalud?', 'answer' => 'Tienes 20 días hábiles desde la fecha en que se generó el pago. Si no cobras dentro de ese plazo, el dinero retorna automáticamente a EsSalud.', 'keywords' => '["cuántos", "días", "tengo", "cobrar", "subsidio", "banco", "antes", "dinero"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué hago si dejé pasar el plazo para cobrar mi subsidio?', 'answer' => 'Ve a una oficina de EsSalud (OSPE) con tu DNI y pide la Rehabilitación de Pago. En unos días hábiles vuelven a habilitar el pago.', 'keywords' => '["hago", "dejé", "pasar", "plazo", "cobrar", "subsidio"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué trámite debo realizar si olvidé cobrar mi subsidio de EsSalud en la fecha programada?', 'answer' => 'Debes ir a una OSPE con tu DNI y pedir la Rehabilitación de Pago. Te pedirán el número de expediente (si lo tienes, mejor). Activarán el pago nuevamente.', 'keywords' => '["trámite", "debo", "realizar", "olvidé", "cobrar", "subsidio", "essalud", "fecha"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cómo me registro por primera vez en la plataforma VIVA?', 'answer' => 'Entras a la web de VIVA, seleccionas "Registrarse", eliges si eres asegurado o empresa, completas tus datos personales (DNI, dígito verificador, datos de contacto) y creas tu contraseña. Te llegará un correo para activar la cuenta.', 'keywords' => '["cómo", "registro", "primera", "plataforma", "viva"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Qué datos necesito obligatoriamente para crear mi cuenta en VIVA?', 'answer' => 'Necesitas: tu número de DNI, el dígito verificador del DNI (número al costado de tu foto), tu fecha de nacimiento, un número de teléfono celular propio y un correo electrónico personal activo.', 'keywords' => '["datos", "necesito", "obligatoriamente", "crear", "cuenta", "viva"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Cómo debe ser mi contraseña para que el sistema la acepte?', 'answer' => 'Debe tener al menos 8 caracteres e incluir obligatoriamente: letras mayúsculas, letras minúsculas, números y al menos un símbolo o carácter especial (como punto, guión o arroba).', 'keywords' => '["cómo", "debe", "contraseña", "sistema", "acepte"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Cómo recupero mi contraseña de VIVA si no me llega el correo?', 'answer' => 'Revisa tu carpeta de "Correo no deseado" o "Spam". Si sigue sin llegar, usa la opción "Olvidé mi contraseña" asegurándote de colocar el correo exacto con el que te registraste. Si persiste, comunícate al soporte técnico de EsSalud en Línea.', 'keywords' => '["cómo", "recupero", "contraseña", "viva", "llega", "correo"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Qué hago si no me llegan las credenciales de acceso a mi correo?', 'answer' => 'Puede deberse a que el correo que registraste tenía un error de digitación. Debes reportarlo a los canales de atención (atencionalasegurado@essalud.gob.pe) para que un asesor limpie tu registro y puedas volver a crear la cuenta correctamente.', 'keywords' => '["hago", "llegan", "credenciales", "acceso", "correo"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué formatos de archivo soporta la plataforma VIVA para subir documentos?', 'answer' => 'Soporta documentos en formato PDF e imágenes en formato JPG o PNG. Se recomienda escanear en blanco y negro o con resolución moderada para que el archivo no sea demasiado pesado.', 'keywords' => '["formatos", "archivo", "soporta", "plataforma", "viva", "subir", "documentos"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué hago si VIVA no me permite adjuntar un PDF?', 'answer' => 'Suele ser por dos motivos: el archivo pesa más de lo permitido (máximo 2MB a 5MB) o el nombre del archivo contiene caracteres extraños (tildes, comas, Ñ). Cambia el nombre del PDF a algo simple (ejemplo: documentosubside.pdf).', 'keywords' => '["hago", "viva", "permite", "adjuntar"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué es la plataforma VIVA y qué trámites puedo hacer ahí?', 'answer' => 'VIVA (Ventanilla Integrada Virtual del Asegurado) es la plataforma oficial de EsSalud para evitar trámites presenciales. Puedes afiliar a tu esposa, conviviente o hijos, actualizar tus datos de domicilio y gestionar el cobro de tus subsidios económicos.', 'keywords' => '["plataforma", "viva", "trámites", "puedo", "hacer"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Para qué sirve el botón "RELLAMAR" en la plataforma VIVA?', 'answer' => 'Es una opción para trámites que se quedaron "trabados" o que requieren atención por error técnico del sistema o una observación que ya fue subsanada, permitiendo reactivar el flujo de revisión de tu expediente.', 'keywords' => '["sirve", "botón", "rellamar", "plataforma", "viva"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué plazo tengo para corregir un trámite observado en VIVA?', 'answer' => 'Cuentas con un plazo habitual de 2 a 5 días hábiles (según la directiva específica) para subir los documentos correctos o subsanar la observación. Si dejas pasar el tiempo, tu trámite será rechazado por abandono.', 'keywords' => '["plazo", "tengo", "corregir", "trámite", "observado", "viva"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cómo creo una cuenta en Mi Consulta?', 'answer' => 'Entras a la web oficial de "Mi Consulta EsSalud" o descargas la app, seleccionas "Registrarse", digitas los datos de tu DNI (número, fecha de emisión) y configuras tus datos de contacto junto a una clave de seguridad.', 'keywords' => '["cómo", "creo", "cuenta", "consulta"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Cómo recupero mi contraseña de Mi Consulta?', 'answer' => 'En la app o web de Mi Consulta, pulsa "¿Olvidaste tu contraseña?". Valida tu identidad ingresando los datos de tu DNI y recibirás un enlace de restauración en tu correo electrónico.', 'keywords' => '["cómo", "recupero", "contraseña", "consulta"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué puedo hacer en la plataforma Mi Consulta?', 'answer' => 'Puedes revisar tus citas médicas programadas, ver en qué centro te atiendes, chequear tus referencias médicas, revisar las recetas y ver las constancias de tus descansos médicos (CITT).', 'keywords' => '["puedo", "hacer", "plataforma", "consulta"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo veo mis recetas médicas en Mi Consulta?', 'answer' => 'Dentro de tu cuenta, dirígete al módulo de "Historial Médico" o "Mis Recetas". Ahí aparecerá la lista completa de los medicamentos que te prescribió el doctor.', 'keywords' => '["cómo", "recetas", "médicas", "consulta"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo veo los resultados de mis exámenes auxiliares en Mi Consulta?', 'answer' => 'Ingresa a la sección "Exámenes de Laboratorio" o "Ayuda al Diagnóstico". El sistema te mostrará la lista de análisis de sangre, placas u otros exámenes listos para visualizar o descargar.', 'keywords' => '["cómo", "resultados", "exámenes", "auxiliares", "consulta"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo veo y descargo mi CITT en Mi Consulta?', 'answer' => 'Ingresa a la pestaña "Mis Descansos Médicos" o "Certificados CITT". Si tu descanso ya fue validado, verás el código oficial del CITT y tendrás un botón para descargarlo en PDF.', 'keywords' => '["cómo", "descargo", "citt", "consulta"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo consulto el estado de una referencia médica en Mi Consulta?', 'answer' => 'Vas a la sección de "Referencias". El sistema te mostrará si tu solicitud ya fue aceptada, qué hospital la recibió y si ya te asignaron fecha y hora para la cita con el especialista.', 'keywords' => '["cómo", "consulto", "estado", "referencia", "médica", "consulta"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es la Mesa de Partes Digital y para qué sirve?', 'answer' => 'Es una ventanilla virtual oficial para que cualquier ciudadano o empresa pueda presentar solicitudes, cartas, formularios o documentos de manera digital sin tener que viajar o hacer colas en una oficina física de EsSalud.', 'keywords' => '["mesa", "partes", "digital", "sirve"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cómo me registro en la Mesa de Partes Digital?', 'answer' => 'Entras al portal web, haces clic en "Crear cuenta", rellenas tus datos personales, ingresas un correo electrónico válido, creas una clave de acceso y confirmas tu registro mediante el enlace que te llegará a tu bandeja de entrada.', 'keywords' => '["cómo", "registro", "mesa", "partes", "digital"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Cómo recupero mi contraseña de la Mesa de Partes Digital?', 'answer' => 'Selecciona el enlace "¿Olvidó su contraseña?". Escribe tu número de DNI y el sistema te enviará un mensaje a tu correo con las instrucciones para generar una nueva clave.', 'keywords' => '["cómo", "recupero", "contraseña", "mesa", "partes", "digital"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el horario de funcionamiento de la Mesa de Partes Digital?', 'answer' => 'Puedes registrar y subir tus documentos las 24 horas, los 7 días de la semana. Sin embargo, los documentos cargados fuera del horario oficial (después de las 4:30 p.m. o en feriados/fin de semana) se consideran presentados a primera hora del día hábil siguiente.', 'keywords' => '["cuál", "horario", "funcionamiento", "mesa", "partes", "digital"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo saber cuál es mi centro de salud asignado?', 'answer' => 'El policlínico se te asigna automáticamente tomando como base la dirección domiciliaria que aparece registrada en tu DNI físico. Puedes consultarlo en la web "¿Dónde me atiendo?".', 'keywords' => '["cómo", "puedo", "saber", "cuál", "centro", "salud", "asignado"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo verifico si mi seguro de EsSalud está activo?', 'answer' => 'Ingresa a www.essalud.gob.pe, busca y haz clic en "¿Dónde me atiendo?", digita los datos del asegurado (nombre o DNI) y presiona "Consultar". El sistema te mostrará si estás activo y cuál es tu centro de salud.', 'keywords' => '["cómo", "verifico", "seguro", "essalud", "está", "activo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el dígito verificador (CUI) y dónde lo encuentro en mi DNI?', 'answer' => 'Es el número único que está en tu DNI físico al costado derecho del número principal, justo después del guión. Ejemplo: si tu DNI es 12345678-9, el dígito verificador es el 9. Sirve para confirmar que el DNI es real.', 'keywords' => '["dígito", "verificador", "dónde", "encuentro"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Cómo actualizo mi domicilio o mis datos personales?', 'answer' => 'Debes presentar el Formulario 1010 (versión 06) correctamente llenado y firmado. Si trabajas para una empresa, debes entregarle el formulario y tus papeles de sustento a tu empleador para que él lo actualice a través del T-Registro de SUNAT.', 'keywords' => '["cómo", "actualizo", "domicilio", "datos", "personales"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Qué hago si no cuento con acreditación vigente para la atención médica?', 'answer' => 'Si estás trabajando pero el hospital te dice que no apareces activo, debes acudir a una OSPE con tu DNI y tus boletas de pago recientes para demostrar que tu empleador te está reteniendo los aportes y el personal te active manualmente en el sistema.', 'keywords' => '["hago", "cuento", "acreditación", "vigente", "atención", "médica"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es la diferencia entre Seguro Regular y Seguro Potestativo?', 'answer' => 'El Seguro Regular lo paga tu empleador, es para trabajadores con empleo formal y es obligatorio. El Seguro Potestativo lo pagas tú mismo, es para independientes o personas sin trabajo, y es voluntario.', 'keywords' => '["cuál", "diferencia", "seguro", "regular", "potestativo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo me afilio al Seguro Potestativo de EsSalud?', 'answer' => '1) Reúne tu DNI (y el de tus derechohabientes). 2) Acude a una OSPE y llena el formulario 1010. 3) Paga tu primer aporte mensual en el Banco de la Nación (costo variable según edad entre S/ 132 y S/ 215 aprox.).', 'keywords' => '["cómo", "afilio", "seguro", "potestativo", "essalud"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿Si soy trabajador independiente y me afilio al seguro potestativo, cuándo empieza mi cobertura para maternidad?', 'answer' => 'Debes estar afiliada y haber pagado 10 meses seguidos antes de que nazca tu bebé (debes estar asegurada desde antes de la concepción; si te afilias ya embarazada, no te cubre el parto).', 'keywords' => '["trabajador", "independiente", "afilio", "seguro", "potestativo", "cuándo", "empieza", "cobertura"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Es posible darse de baja voluntariamente de un seguro de EsSalud?', 'answer' => 'Sí, pero solo del Seguro Potestativo. El seguro regular no se puede cancelar porque es obligatorio. Para la baja del potestativo, presentas una carta formal firmada junto a tu DNI en una OSPE.', 'keywords' => '["posible", "darse", "baja", "voluntariamente", "seguro", "essalud"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Qué significa la cobertura por desempleo (latencia) y cuánto dura?', 'answer' => 'Es un beneficio que te permite seguir atendiéndote gratis en los hospitales si te quedas sin trabajo. Dura según tus aportes en los últimos 3 años: 5-9 meses aportados = 2 meses; 10-14 = 4 meses; 15-19 = 6 meses; 20-24 = 8 meses; 25-29 = 10 meses; 30-36 = 12 meses (máximo).', 'keywords' => '["significa", "cobertura", "desempleo", "latencia", "cuánto", "dura"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Puedo atenderme inmediatamente si acabo de conseguir trabajo?', 'answer' => 'Solo si sufres una emergencia médica por accidente, ya que ante un accidente el seguro te cubre desde el primer día. Para consultas comunes, debes esperar 3 meses (periodo de carencia).', 'keywords' => '["puedo", "atenderme", "inmediatamente", "acabo", "conseguir", "trabajo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si mi empleador no ha pagado el seguro este mes?', 'answer' => 'Como trabajador dependiente no pierdes la atención de forma inmediata si tienes aportes consecutivos anteriores. EsSalud atenderá tu consulta y luego le cobrará los gastos médicos a tu empresa morosa.', 'keywords' => '["pasa", "empleador", "pagado", "seguro"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Me pueden descontar el 9% de mi sueldo para pagar el seguro?', 'answer' => 'No. El aporte del 9% para EsSalud es de cargo exclusivo de la empresa empleadora. Tu empleador no te puede quitar ni un solo sol de tu sueldo neto para este concepto.', 'keywords' => '["pueden", "descontar", "sueldo", "pagar", "seguro"]'],
            ['category_name' => 'Cuenta y Perfil', 'question' => '¿Qué es el Seguro Agrario de EsSalud y quiénes pueden acceder?', 'answer' => 'Es un seguro especial con tasas de aporte diferenciadas para proteger a trabajadores que realizan actividades de cultivo, crianza de animales o agroindustria, ya sea que trabajen para una empresa del campo o de forma independiente.', 'keywords' => '["seguro", "agrario", "essalud", "quiénes", "pueden", "acceder"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Si soy trabajador agrario independiente y tengo una empresa unipersonal, puedo afiliarme?', 'answer' => 'No. La normativa prohíbe la afiliación al Seguro Agrario Independiente a personas naturales que sean titulares de empresas unipersonales.', 'keywords' => '["trabajador", "agrario", "independiente", "tengo", "empresa", "unipersonal", "puedo", "afiliarme"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el costo del aporte para una pequeña empresa agraria en 2026?', 'answer' => 'Si la empresa tiene menos de 100 trabajadores o ventas menores a 1700 UIT, la tasa de aporte para 2026 es del 6%.', 'keywords' => '["cuál", "costo", "aporte", "pequeña", "empresa", "agraria"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Si me afilio hoy y tengo un accidente mañana, el seguro me cubre?', 'answer' => 'Sí. A pesar de que existe un periodo de carencia de 3 meses, en casos de accidente o emergencia sanitaria, la cobertura es inmediata.', 'keywords' => '["afilio", "tengo", "accidente", "mañana", "seguro", "cubre"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el +Vida Seguro de Accidentes de EsSalud?', 'answer' => 'Es un seguro de accidentes personal y voluntario con un costo muy bajo (S/ 5 al mes). Protege al titular y a su cónyuge las 24 horas del día, los 365 días del año (incluso en el extranjero), otorgando indemnización en caso de invalidez permanente o fallecimiento por accidente.', 'keywords' => '["vida", "seguro", "accidentes", "essalud"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Quiénes pueden afiliarse al +Vida?', 'answer' => 'Todos los asegurados titulares de EsSalud que tengan entre 15 y 70 años cumplidos, pertenecientes al régimen regular, seguro agrario, seguro potestativo o pescadores artesanales.', 'keywords' => '["quiénes", "pueden", "afiliarse", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuánto cuesta la prima mensual del +Vida?', 'answer' => 'Tiene un costo de S/ 5.00 mensuales. No se incrementa por criterios de edad ni por el estado médico del afiliado.', 'keywords' => '["cuánto", "cuesta", "prima", "mensual", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿El +Vida reemplaza mi seguro regular de EsSalud?', 'answer' => 'No. Es un seguro financiero complementario. La atención médica en los hospitales se sigue rigiendo por tu seguro regular de salud. El +Vida actúa como un fondo de indemnización económica ante un accidente.', 'keywords' => '["vida", "reemplaza", "seguro", "regular", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo me afilio al +Vida si soy trabajador independiente?', 'answer' => 'Llenas el Formulario 6012 con tus datos y beneficiarios, lo presentas físicamente en una OSPE y luego pagas S/ 5.00 mensuales en el Banco de la Nación con tu número de contrato.', 'keywords' => '["cómo", "afilio", "vida", "trabajador", "independiente"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo designo a mis beneficiarios en el seguro +Vida?', 'answer' => 'En la sección 3 del Formulario 6012, indicando nombres completos, DNI y asignando un porcentaje exacto de la indemnización a cada uno. La suma de todos los porcentajes debe ser exactamente 100%.', 'keywords' => '["cómo", "designo", "beneficiarios", "seguro", "vida"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el Seguro Complementario de Trabajos de Riesgo (SCTR)?', 'answer' => 'Es un seguro obligatorio que tu empleador debe contratar si trabajas en actividades consideradas de alto riesgo (minería, construcción, pesca, industrias). Asegura atención médica al 100% gratis por accidentes laborales o enfermedades profesionales, y otorga pensiones por invalidez o fallecimiento.', 'keywords' => '["seguro", "complementario", "trabajos", "riesgo", "sctr"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué cubre el SCTR?', 'answer' => 'Cubre todas las prestaciones médicas (consultas, cirugías, hospitalización, medicinas, prótesis, rehabilitación) derivadas de accidente de trabajo o enfermedad profesional. También cubre pensiones de invalidez o sobrevivencia.', 'keywords' => '["cubre", "sctr"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el código CIIU y dónde lo encuentro?', 'answer' => 'Es la Clasificación Industrial Internacional Uniforme, un código numérico que identifica la actividad económica exacta de un contribuyente. Lo encuentras en tu ficha RUC de SUNAT.', 'keywords' => '["código", "ciiu", "dónde", "encuentro"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el valor de la UIT para el año 2026?', 'answer' => 'El valor de la UIT para el año 2026 es de S/ 5,500.', 'keywords' => '["cuál", "valor"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuánto cuesta un Informe Médico en 2026?', 'answer' => 'El costo es S/ 37.10, lo que representa el 0.675% de la UIT 2026.', 'keywords' => '["cuánto", "cuesta", "informe", "médico"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Cuánto cuesta el Dictamen Médico para hijos mayores incapacitados?', 'answer' => 'Tiene un costo fijo de S/ 180.00, que representa el 3.273% de la UIT 2026.', 'keywords' => '["cuánto", "cuesta", "dictamen", "médico", "hijos", "mayores", "incapacitados"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuál es el costo por folio de una copia de Historia Clínica?', 'answer' => 'El costo es de S/ 0.10 por folio, equivalente al 0.002% de la UIT.', 'keywords' => '["cuál", "costo", "folio", "copia", "historia", "clínica"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el costo del Duplicado del Certificado de Incapacidad Temporal (CITT)?', 'answer' => 'El costo es de S/ 10.20, representando el 0.185% de la UIT 2026.', 'keywords' => '["cuál", "costo", "duplicado", "certificado", "incapacidad", "temporal", "citt"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es la Visita Domiciliaria Integral (VDI)?', 'answer' => 'Es una atención médica que brinda el equipo de salud directamente en la casa del paciente. Está diseñada para personas que no pueden moverse por sus propios medios, pacientes postrados, adultos mayores con enfermedades crónicas avanzadas o recién nacidos con alto riesgo.', 'keywords' => '["visita", "domiciliaria", "integral"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Es obligatorio dejar entrar al equipo médico a mi casa?', 'answer' => 'No es una obligación legal por la fuerza. Si estás afiliado a un programa de atención domiciliaria (como Padomi), es requisito para recibir el beneficio. El personal debe ingresar para revisarte y verificar tu entorno.', 'keywords' => '["obligatorio", "dejar", "entrar", "equipo", "médico", "casa"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué evalúa el personal en mi domicilio además de mi salud?', 'answer' => 'Evalúan el entorno: si tu habitación tiene buena ventilación y luz, la higiene, cómo guardan tus medicinas y riesgos de caídas (cables sueltos, alfombras resbaladizas).', 'keywords' => '["evalúa", "personal", "domicilio", "además", "salud"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo saco una cita médica en EsSalud?', 'answer' => 'Puedes solicitarla llamando a "EsSalud en Línea" de tu región, a través de la app Mi Consulta EsSalud, o acercándote a los módulos de citas de tu policlínico asignado.', 'keywords' => '["cómo", "saco", "cita", "médica", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuál es el número de EsSalud en Línea de mi departamento?', 'answer' => 'Lima: (01)411-8000; Arequipa: (054)22-6969; Cusco: (084)58-1150; La Libertad: (044)48-5030; Lambayeque: (074)48-1060; Piura: (073)28-4760; Ica: (056)58-1060.', 'keywords' => '["cuál", "número", "essalud", "línea", "departamento"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuánto tiempo antes debo llegar a mi cita médica?', 'answer' => 'Se recomienda llegar al menos 30 minutos antes si es cita común, y hasta 45 minutos antes si debes pasar primero por triaje.', 'keywords' => '["cuánto", "tiempo", "antes", "debo", "llegar", "cita", "médica"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué documentos necesito para asistir a mi cita médica?', 'answer' => 'Solo necesitas llevar tu DNI físico y vigente. Si eres extranjero, tu Carnet de Extranjería o Pasaporte registrado en el sistema.', 'keywords' => '["documentos", "necesito", "asistir", "cita", "médica"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cómo cancelo o reprogramo una cita médica?', 'answer' => 'Debes hacerlo llamando a EsSalud en Línea o a través de Mi Consulta con un mínimo de 48 horas de anticipación.', 'keywords' => '["cómo", "cancelo", "reprogramo", "cita", "médica"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Dónde encuentro tutoriales en video para usar las plataformas de EsSalud?', 'answer' => 'Los encuentras en el canal oficial de YouTube de EsSalud ("EsSalud Perú") o en las secciones de ayuda del Portal Institucional (www.essalud.gob.pe).', 'keywords' => '["dónde", "encuentro", "tutoriales", "video", "usar", "plataformas", "essalud"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué es el NIT (Número Interno de Trámite) y para qué sirve?', 'answer' => 'Es un código único que funciona como el "DNI de tu trámite". Sirve para rastrear digitalmente tu expediente y saber en qué oficina se encuentra o si ya está listo para pagarse.', 'keywords' => '["número", "interno", "trámite", "sirve"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cómo puedo reportar un problema técnico con una plataforma de EsSalud?', 'answer' => 'Puedes llamar al 411-8000 (Lima), usar el Libro de Reclamaciones del portal web, o enviar un correo detallado con capturas de pantalla a atencionalasegurado@essalud.gob.pe.', 'keywords' => '["cómo", "puedo", "reportar", "problema", "técnico", "plataforma", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Dónde encuentro la oficina OSPE más cercana a mi domicilio?', 'answer' => 'La lista de OSPE con direcciones exactas a nivel nacional está publicada en el portal web institucional de EsSalud, ubicadas usualmente en las capitales de provincia.', 'keywords' => '["dónde", "encuentro", "oficina", "ospe", "cercana", "domicilio"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuál es el horario de atención de las oficinas OSPE?', 'answer' => 'El horario habitual es de lunes a viernes desde las 8:00 a.m. hasta las 4:00 p.m. o 4:30 p.m. No laboran sábados, domingos ni feriados.', 'keywords' => '["cuál", "horario", "atención", "oficinas", "ospe"]'],
            ['category_name' => 'Afiliaciones', 'question' => '¿Quién puede afiliarse al Seguro Potestativo de EsSalud?', 'answer' => 'Pueden afiliarse personas sin cobertura laboral: trabajadores independientes, universitarios, practicantes, emprendedores, peruanos y extranjeros residentes. No pueden afiliarse asegurados activos del Seguro Regular, Agrario o de otro Potestativo, ni afiliados al SIS.', 'keywords' => '["quién", "puede", "afiliarse", "seguro", "potestativo", "essalud"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Cuánto cuesta el Seguro Potestativo +Salud según mi edad?', 'answer' => 'Los montos mensuales son: 0-17 años: S/ 137; 18-29 años: S/ 132; 30-59 años: S/ 138; 60 años a más: S/ 215. Los montos incluyen IGV.', 'keywords' => '["cuánto", "cuesta", "seguro", "potestativo", "salud", "según", "edad"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuánto tiempo tengo que esperar para recibir atención médica después de afiliarme al potestativo?', 'answer' => 'El período de carencia es de 3 meses para cobertura completa. Sin embargo, las emergencias médicas accidentales están cubiertas desde el primer día de vigencia, durante las primeras 24 horas de ocurrida la emergencia.', 'keywords' => '["cuánto", "tiempo", "tengo", "esperar", "recibir", "atención", "médica", "después"]'],
            ['category_name' => 'Subsidio por Maternidad', 'question' => '¿El seguro potestativo cubre el parto y el embarazo?', 'answer' => 'Sí, cubre maternidad pero con condiciones: la asegurada debe estar afiliada al momento de la concepción (no cubre si se afilia estando ya embarazada). El período de espera para maternidad es de 10 meses. El puerperio cubre 42 días después del parto. También cubre a hijas derechohabientes.', 'keywords' => '["seguro", "potestativo", "cubre", "parto", "embarazo"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué documentos necesito para afiliarme al Seguro Potestativo?', 'answer' => 'Para afiliación individual: DNI o carnet de extranjería vigente, Contrato suscrito, Formulario 1010 lleno sin borrones. Para cónyuge: acta de matrimonio (antigüedad ≤6 meses). Para concubino(a): reconocimiento de unión de hecho. Para hijos menores: acta de nacimiento. Para hijos mayores incapacitados: dictamen médico de EsSalud.', 'keywords' => '["documentos", "necesito", "afiliarme", "seguro", "potestativo"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Qué pasa si no pago mi aporte del seguro potestativo a tiempo?', 'answer' => 'La cobertura se suspende automáticamente al día siguiente del vencimiento. Se puede rehabilitar pagando los aportes pendientes más intereses moratorios. Si el afiliado no paga 2 meses consecutivos, el contrato se resuelve automáticamente.', 'keywords' => '["pasa", "pago", "aporte", "seguro", "potestativo", "tiempo"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el TUPA de EsSalud y para qué sirve?', 'answer' => 'El TUPA (Texto Único de Procedimientos Administrativos) es el documento que contiene todos los procedimientos administrativos y servicios prestados en exclusividad de EsSalud. Establece requisitos, plazos, costos y canales de atención para cada trámite, garantizando predictibilidad al ciudadano.', 'keywords' => '["tupa", "essalud", "sirve"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué plazo tiene EsSalud para responder mi solicitud de subsidio?', 'answer' => 'El plazo máximo para resolver solicitudes de prestaciones económicas (subsidios) es de 15 días hábiles. Si EsSalud no responde dentro de ese plazo, se aplica el silencio administrativo negativo, lo que significa que la solicitud se considera denegada para efectos de apelación.', 'keywords' => '["plazo", "tiene", "essalud", "responder", "solicitud", "subsidio"]'],
            ['category_name' => 'Consultas Médicas', 'question' => '¿Cuánto cuesta sacar una copia de mi Historia Clínica?', 'answer' => 'El costo es de S/ 0.10 por cada folio (hoja). El plazo de entrega es de 5 días hábiles.', 'keywords' => '["cuánto", "cuesta", "sacar", "copia", "historia", "clínica"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué es el "Silencio Administrativo Negativo" en mis trámites?', 'answer' => 'Es una figura legal que opera cuando EsSalud supera el plazo máximo (15 días hábiles para subsidios) sin emitir respuesta. La solicitud se considera denegada automáticamente, lo que permite al administrado interponer un recurso de apelación ante una instancia superior.', 'keywords' => '["silencio", "administrativo", "negativo", "trámites"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué dice la ley sobre los primeros 20 días de incapacidad?', 'answer' => 'Según el Decreto Supremo N° 013-2019-TR, los primeros 20 días de incapacidad en el año calendario son pagados por el empleador. EsSalud asume el subsidio recién a partir del día 21 de incapacidad, hasta un máximo de 11 meses y 10 días consecutivos.', 'keywords' => '["dice", "primeros", "días", "incapacidad"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué pasa si mi empleador no me paga los primeros 20 días de incapacidad?', 'answer' => 'Si el empleador no paga los primeros 20 días, está incumpliendo la ley. El trabajador puede reclamar a EsSalud para que pague el subsidio desde el día 1, y EsSalud luego le cobrará al empleador. También se puede denunciar al empleador en SUNAFIL.', 'keywords' => '["pasa", "empleador", "paga", "primeros", "días", "incapacidad"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cómo se calcula el monto de mi subsidio por maternidad?', 'answer' => 'Se calcula con el promedio diario de las remuneraciones asegurables de los últimos 12 meses. No se incluyen gratificaciones (Fiestas Patrias, Navidad). Sí se incluyen horas extras y sobretiempos. El monto diario, una vez calculado, no varía aunque cambie la remuneración durante la incapacidad.', 'keywords' => '["cómo", "calcula", "monto", "subsidio", "maternidad"]'],
            ['category_name' => 'Consultas Generales', 'question' => '¿Qué es el Informe IMECI y para qué sirve?', 'answer' => 'El IMECI (Informe Médico de Calificación de Incapacidades) lo emite una comisión médica cuando: hay incapacidad permanente, pronóstico reservado, 150 días consecutivos de incapacidad, o 90 días no consecutivos en 365 días por misma patología. Si declara incapacidad temporal, tiene validez de 6 meses.', 'keywords' => '["informe", "imeci", "sirve"]'],
            ['category_name' => 'Trámites y Documentos', 'question' => '¿Qué es el Formulario de Aviso de Accidente de Trabajo y cómo se usa?', 'answer' => 'Es el documento clave para activar la cobertura del SCTR ante un accidente laboral. Debe ser llenado por el empleador (o el trabajador independiente) con nombre y DNI del accidentado, RUC y nombre de la empresa. Puede regularizarse dentro de los 5 días hábiles siguientes al accidente.', 'keywords' => '["formulario", "aviso", "accidente", "trabajo", "cómo"]'],
            ['category_name' => 'Prestaciones Económicas', 'question' => '¿Cuánto pago de aporte mensual al SCTR como trabajador independiente?', 'answer' => 'El aporte se calcula con la fórmula: (½ de la UIT vigente) × (tasa según nivel de riesgo). Por ejemplo, para Nivel III (1.53%) con UIT 2025 de S/5,350, el aporte sería S/40.93 mensual. Se paga en el Banco de la Nación. El monto cambia cada año con la actualización de la UIT.', 'keywords' => '["cuánto", "pago", "aporte", "mensual", "sctr", "trabajador", "independiente"]'],
